 * Update event from Maximo status change.
 * Called by Maximo webhook receiver.
 */
async updateFromMaximo(
  externalReference: string,
  maximoStatus: string,
  updates?: Partial<{
    estimatedRepairHours: number;
    estimatedReturnDate: string;
    description: string;
    failureCode: string;
  }>
): Promise<UnavailabilityEvent | null> {
  return this.inTransaction('updateFromMaximo', async (tx, span) => {
    span.setAttribute('maximo.reference', externalReference);
    span.setAttribute('maximo.status', maximoStatus);

    const event = await tx.query.unavailabilityEvents.findFirst({
      where: and(
        eq(unavailabilityEvents.sourceSystem, 'MAXIMO'),
        eq(unavailabilityEvents.externalReference, externalReference)
      ),
    });

    if (!event) {
      this.log.warn(
        { externalReference, maximoStatus },
        'Maximo status update for unknown event - ignoring'
      );
      return null;
    }

    // Map Maximo status to event status
    // COMP, CLOSE, CAN = resolved
    const isResolved = ['COMP', 'CLOSE', 'CAN'].includes(maximoStatus);

    if (isResolved && event.status === 'ACTIVE') {
      // Resolve the event
      const [resolved] = await tx
        .update(unavailabilityEvents)
        .set({
          status: 'RESOLVED',
          externalStatus: maximoStatus,
          actualReturnDate: new Date().toISOString().split('T')[0],
          resolvedAt: new Date(),
          resolutionNotes: `Resolved via Maximo status: ${maximoStatus}`,
          updatedAt: new Date(),
          ...updates,
        })
        .where(eq(unavailabilityEvents.id, event.id))

