     1вҶ’/**
     2вҶ’ * MMS Workers - Central Exports
     3вҶ’ *
     4вҶ’ * BullMQ worker infrastructure for background job processing.
     5вҶ’ * Each worker processes jobs from its designated queue with
     6вҶ’ * consistent error handling, tracing, and metrics.
     7вҶ’ *
     8вҶ’ * Worker Types:
     9вҶ’ * - ingestion: CSV file processing and mileage data import
    10вҶ’ * - tactical_scheduler: PM scheduling within 12-week horizon
    11вҶ’ * - strategic_planner: Long-term (10-year) PM planning
    12вҶ’ * - optimizer: Run assignment optimization (C++ CP-SAT or TS fallback)
    13вҶ’ * - manhour_leveling: Workload balancing across periods
    14вҶ’ * - drift_monitor: Baseline comparison and drift detection
    15вҶ’ * - notification: Email and alert sending
    16вҶ’ * - report: PDF/Excel report generation
    17вҶ’ *
    18вҶ’ * @see specs/004-domain-services.md Section 4.8
    19вҶ’ * @see specs/002-architecture.md Section 2.4 - Worker Layer
    20вҶ’ */
    21вҶ’
    22вҶ’import { Worker, type WorkerOptions, type Job } from 'bullmq';
    23вҶ’import { logger } from '../lib/logging/logger';
    24вҶ’import { QUEUE_NAMES, type QueueName, type JobData } from '../lib/queue';
    25вҶ’import { withSpan } from '../lib/tracing';
    26вҶ’import { toMmsError, QueueError } from '../lib/errors';
    27вҶ’import { workerMetrics } from '../lib/metrics';
    28вҶ’
    29вҶ’// =============================================================================
    30вҶ’// Worker Configuration
    31вҶ’// =============================================================================
    32вҶ’
    33вҶ’/**
    34вҶ’ * Default worker options applied to all workers
    35вҶ’ */
    36вҶ’export const DEFAULT_WORKER_OPTIONS: Partial<WorkerOptions> = {
    37вҶ’  concurrency: 1,
    38вҶ’  autorun: true,
    39вҶ’  lockDuration: 30000, // 30 seconds
    40вҶ’  lockRenewTime: 15000, // 15 seconds
    41вҶ’  limiter: undefined, // No rate limiting by default
    42вҶ’};
    43вҶ’
    44вҶ’/**
    45вҶ’ * Worker-specific configurations
    46вҶ’ */
    47вҶ’export const WORKER_CONFIGS: Record<
    48вҶ’  keyof typeof QUEUE_NAMES,
    49вҶ’  { concurrency: number; lockDuration: number; description: string }
    50вҶ’> = {
    51вҶ’  INGESTION: {
    52вҶ’    concurrency: 1, // Sequential to avoid race conditions
    53вҶ’    lockDuration: 60000, // 1 minute for file processing
    54вҶ’    description: 'CSV file processing and mileage data import',
    55вҶ’  },
    56вҶ’  TACTICAL_SCHEDULER: {
    57вҶ’    concurrency: 1, // Single scheduler to maintain consistency
    58вҶ’    lockDuration: 300000, // 5 minutes for scheduling
    59вҶ’    description: 'PM scheduling within 12-week horizon',
    60вҶ’  },
    61вҶ’  STRATEGIC_PLANNER: {
    62вҶ’    concurrency: 1, // Single planner for GA optimization
    63вҶ’    lockDuration: 600000, // 10 minutes for long-term planning
    64вҶ’    description: 'Long-term (10-year) PM planning with genetic algorithm',
    65вҶ’  },
    66вҶ’  OPTIMIZER: {
    67вҶ’    concurrency: 2, // Can run multiple optimizations in parallel
    68вҶ’    lockDuration: 60000, // 1 minute per optimization
    69вҶ’    description: 'Run assignment optimization (C++ CP-SAT or TS fallback)',
    70вҶ’  },
    71вҶ’  MANHOUR_LEVELING: {
    72вҶ’    concurrency: 1, // Sequential processing
    73вҶ’    lockDuration: 120000, // 2 minutes
    74вҶ’    description: 'Workload balancing across periods',
    75вҶ’  },
    76вҶ’  DRIFT_MONITOR: {
    77вҶ’    concurrency: 2, // Can analyze multiple baselines
    78вҶ’    lockDuration: 60000, // 1 minute
    79вҶ’    description: 'Baseline comparison and drift detection',
    80вҶ’  },
    81вҶ’  NOTIFICATION: {
    82вҶ’    concurrency: 5, // High concurrency for notifications
    83вҶ’    lockDuration: 30000, // 30 seconds
    84вҶ’    description: 'Email and alert sending',
    85вҶ’  },
    86вҶ’  REPORT: {
    87вҶ’    concurrency: 2, // PDF/Excel generation
    88вҶ’    lockDuration: 120000, // 2 minutes for report generation
    89вҶ’    description: 'PDF/Excel report generation',
    90вҶ’  },
    91вҶ’};
    92вҶ’
    93вҶ’// =============================================================================
    94вҶ’// Redis Configuration
    95вҶ’// =============================================================================
    96вҶ’
    97вҶ’function getRedisConfig() {
    98вҶ’  return {
    99вҶ’    host: process.env['REDIS_HOST'] ?? 'localhost',
   100вҶ’    port: parseInt(process.env['REDIS_PORT'] ?? '6379', 10),
   101вҶ’    password: process.env['REDIS_PASSWORD'],
   102вҶ’    maxRetriesPerRequest: null as null, // Required for BullMQ
   103вҶ’  };
   104вҶ’}
   105вҶ’
   106вҶ’// =============================================================================
   107вҶ’// Base Worker Types
   108вҶ’// =============================================================================
   109вҶ’
   110вҶ’/**
   111вҶ’ * Job context passed to processor functions
   112вҶ’ */
   113вҶ’export interface WorkerJobContext<T extends JobData = JobData> {
   114вҶ’  /** Job ID */
   115вҶ’  id: string;
   116вҶ’  /** Job name */
   117вҶ’  name: string;
   118вҶ’  /** Job data payload */
   119вҶ’  data: T;
   120вҶ’  /** Job attempt number (1-based) */
   121вҶ’  attemptsMade: number;
   122вҶ’  /** Update job progress (0-100) */
   123вҶ’  updateProgress: (progress: number | object) => Promise<void>;
   124вҶ’  /** Add log message to job */
   125вҶ’  log: (message: string) => Promise<void>;
   126вҶ’}
   127вҶ’
   128вҶ’/**
   129вҶ’ * Worker processor function signature
   130вҶ’ */
   131вҶ’export type WorkerProcessor<T extends JobData = JobData, R = unknown> = (
   132вҶ’  context: WorkerJobContext<T>
   133вҶ’) => Promise<R>;
   134вҶ’
   135вҶ’/**
   136вҶ’ * Worker registration result
   137вҶ’ */
   138вҶ’export interface RegisteredWorker {
   139вҶ’  /** Worker instance */
   140вҶ’  worker: Worker;
   141вҶ’  /** Queue name */
   142вҶ’  queueName: QueueName;
   143вҶ’  /** Worker description */
   144вҶ’  description: string;
   145вҶ’  /** Graceful shutdown function */
   146вҶ’  close: () => Promise<void>;
   147вҶ’}
